// Latest returns the newest row for key, tombstone-blind (the raw
// row-level primitive — a deleted key still returns its tombstone
// row; GetLive is the interpreted state-view read). Reads see only
// flushed rows.
func (inst *PushoutStore) Latest(ctx context.Context, key string) (ent *PushoutEntity, found bool, err error) {
	sql := "SELECT * FROM " + PushoutTableName +
		" WHERE " + PushoutColKey + " = " + pushoutKeyLiteral(key) +
		" ORDER BY " + PushoutColOrder + " DESC LIMIT 1" + pushoutArrowOutputSettings
	ents, err := inst.queryEntities(ctx, sql)
	if err != nil || len(ents) == 0 {
		return
	}
	ent = ents[0]
	found = true
	return
}

// Replay iterates the rows for key with the order column >= fromOrder
// in ascending order — the event-replay primitive. A zero fromOrder
// replays everything (zero time.Time has no defined UnixNano;
// recordstore.SeqTs(0) is the equivalent explicit bound);
// opts.To bounds the replay exclusively ("state as of To") and
// opts.Limit caps the row count. The sequence is single-use; ctx
// must stay valid until iteration completes; the query may execute
// at call time or lazily during iteration (buffered in v1 — a
// streaming executor changes nothing visible); an error ends the
// sequence as a final (nil, err) pair. Reads see only flushed rows.
func (inst *PushoutStore) Replay(ctx context.Context, key string, fromOrder time.Time, opts recordstore.ReplayOpts) iter.Seq2[*PushoutEntity, error] {
	sql := "SELECT * FROM " + PushoutTableName +
		" WHERE " + PushoutColKey + " = " + pushoutKeyLiteral(key)
	if !fromOrder.IsZero() {
		sql += " AND " + PushoutColOrder + " >= fromUnixTimestamp64Nano(" + strconv.FormatInt(fromOrder.UnixNano(), 10) + ")"
	}
	if !opts.To.IsZero() {
		sql += " AND " + PushoutColOrder + " < fromUnixTimestamp64Nano(" + strconv.FormatInt(opts.To.UnixNano(), 10) + ")"
	}
	sql += " ORDER BY " + PushoutColOrder + " ASC"
	if opts.Limit > 0 {
		sql += " LIMIT " + strconv.Itoa(opts.Limit)
	}
	sql += pushoutArrowOutputSettings
	return inst.iterateEntities(ctx, sql)
}

// --- state view (Delete / GetLive; ADR-0100 SD4). Versioned writes
// go through Begin — appending a new version IS the update. ---

// Delete appends a tombstone row for id (no components; lifecycle marks
// the deletion). The tombstone writes through to attached cache views
// like any commit — a versioned deletion, so GetLive reads the key as
// absent immediately.
func (inst *PushoutStore) Delete(id string, ts time.Time) (err error) {
	inst.dml.BeginEntity().SetId(id).SetTimestamp(ts).SetLifecycle(recordstore.LifecycleTombstone)
	err = inst.dml.CommitEntity()
	if err != nil {
		_ = inst.dml.RollbackEntity() // discard the failed frame; the store stays usable
		return
	}
	inst.buffered++
	inst.dirty[id] = struct{}{}
	inst.notifyWrite(id, &PushoutEntity{ID: id, Ts: ts, Lifecycle: recordstore.LifecycleTombstone})
	return
}

// GetLive is Latest plus tombstone interpretation: newest row wins, a
// tombstone reads as absent — the state-view read (the cache view
// carries the cached twin).
func (inst *PushoutStore) GetLive(ctx context.Context, key string) (ent *PushoutEntity, found bool, err error) {
	ent, found, err = inst.Latest(ctx, key)
	if err != nil || !found {
		return
	}
	if ent.IsTombstone() {
		ent = nil
		found = false
	}
	return
}

// --- decode (Arrow → entity bags). ---

// pushoutSectionReaderI is the uniform slice of the generated read-access
// readers. Column indices stay at their constructor defaults — the
// schema order a SELECT * returns.
type pushoutSectionReaderI interface {
	LoadFromRecord(raruntime.RecordI) error
	Release()
}

func (inst *PushoutStore) queryEntities(ctx context.Context, sql string) (ents []*PushoutEntity, err error) {
	for rec, rerr := range inst.exec.QueryArrow(ctx, sql) {
		if rerr != nil {
			err = eh.Errorf("query entities: %w", rerr)
			return
		}
		batch, derr := decodePushoutRecord(rec)
		rec.Release()
		if derr != nil {
			err = derr
			return
		}
		ents = append(ents, batch...)
	}
	return
}

// iterateEntities adapts the buffered query path to the single-use
// iterator contract shared by Replay and the Scan verbs: entities
// yield in query order; an error yields once as (nil, err) and ends
// the sequence.
func (inst *PushoutStore) iterateEntities(ctx context.Context, sql string) iter.Seq2[*PushoutEntity, error] {
	return func(yield func(*PushoutEntity, error) bool) {
		ents, err := inst.queryEntities(ctx, sql)
		if err != nil {
			yield(nil, err)
			return
		}
		for _, ent := range ents {
			if !yield(ent, nil) {
				return
			}
		}
	}
}

// decodePushoutRecord reads one fetched Arrow record into entity bags:
// envelope from the plain readers, components via presence-gated,
// membership-matched reads (fat rows carry optional components — the
// kind-homogeneous helpers cannot decode them).
func decodePushoutRecord(rec arrow.RecordBatch) (ents []*PushoutEntity, err error) {
	idR := lowlevel.NewReadAccessPushoutTablePlainEntityIdAttributes()
	tsR := lowlevel.NewReadAccessPushoutTablePlainEntityTimestampAttributes()
	lcR := lowlevel.NewReadAccessPushoutTablePlainEntityLifecycleAttributes()
	envBlobR := lowlevel.NewReadAccessPushoutTableTaggedEnvBlob()
	logHashR := lowlevel.NewReadAccessPushoutTableTaggedLogHash()
	snapAppliedR := lowlevel.NewReadAccessPushoutTableTaggedSnapApplied()
	snapGraggleR := lowlevel.NewReadAccessPushoutTableTaggedSnapGraggle()
	retHashR := lowlevel.NewReadAccessPushoutTableTaggedRetHash()
	retIndexR := lowlevel.NewReadAccessPushoutTableTaggedRetIndex()
	retTimeR := lowlevel.NewReadAccessPushoutTableTaggedRetTime()
	readers := []pushoutSectionReaderI{idR, tsR, lcR, envBlobR, logHashR, snapAppliedR, snapGraggleR, retHashR, retIndexR, retTimeR}
	for _, r := range readers {
		err = r.LoadFromRecord(rec)
		if err != nil {
			err = eh.Errorf("load pushout reader from record: %w", err)
			return
		}
	}
	defer func() {
		for _, r := range readers {
			r.Release()
		}
	}()

	n := idR.ValueId.Len()
	tsType, ok := tsR.ValueTs.DataType().(*arrow.TimestampType)
	if !ok {
		err = eh.Errorf("order column is not a timestamp (got %s)", tsR.ValueTs.DataType())
		return
	}
	ents = make([]*PushoutEntity, 0, n)
	for i := range n {
		ent := &PushoutEntity{
			ID:        idR.ValueId.Value(i),
			Ts:        tsR.ValueTs.Value(i).ToTime(tsType.Unit).UTC(),
			Lifecycle: lcR.ValueLifecycle.Value(i),
		}
		{
			row, ok, e := envelopeReadRow(i, envBlobR.GetAttributes(), envBlobR.GetMemberships())
			if e != nil {
				err = eh.Errorf("read envelope component: %w", e)
				return
			}
			if ok {
				row.ID = ent.ID
				ent.Envelope = option.Some(row)
			}
		}
		{
			row, ok, e := logEntryReadRow(i, logHashR.GetAttributes(), logHashR.GetMemberships())
			if e != nil {
				err = eh.Errorf("read logEntry component: %w", e)
				return
			}
			if ok {
				row.ID = ent.ID
				ent.LogEntry = option.Some(row)
			}
		}
		{
			row, ok, e := snapshotReadRow(i, snapAppliedR.GetAttributes(), snapAppliedR.GetMemberships(), snapGraggleR.GetAttributes(), snapGraggleR.GetMemberships())
			if e != nil {
				err = eh.Errorf("read snapshot component: %w", e)
				return
			}
			if ok {
				row.ID = ent.ID
				ent.Snapshot = option.Some(row)
			}
		}
		{
			row, ok, e := retentionReadRow(i, retHashR.GetAttributes(), retHashR.GetMemberships(), retIndexR.GetAttributes(), retIndexR.GetMemberships(), retTimeR.GetAttributes(), retTimeR.GetMemberships())
			if e != nil {
				err = eh.Errorf("read retention component: %w", e)
				return
			}
			if ok {
				row.ID = ent.ID
				ent.Retention = option.Some(row)
			}
		}
		ents = append(ents, ent)
	}
	return
}
